import loggingfrom .ModbusTCPMeasurements import get_modbus_serverimport osfrom influxdb_client import InfluxDBClient, WriteOptionsdef init_communication(config_data):    """    Initializes the communication protocol specified in the configuration file.    Depending on the protocol (e.g., Modbus, IEC61850), this function sets up the necessary server.    :param config_data: Configuration dictionary containing application settings, including the communication protocol.    :return: The server initialized for the communication protocol.    """    try:        protocol = config_data['Aas_config']['application']['communication_protocol']        logging.info(f"Initializing communication protocol: {protocol}")        if protocol == 'modbus':            logging.info("Initializing Modbus server.")            server = get_modbus_server(config_data)            logging.info("Modbus server initialized successfully.")        elif protocol == 'iec61850':            logging.info("IEC 61850 communication protocol selected, but functionality is not implemented.")            # server = getIEC61850Server(gridData)            server = None        else:            logging.warning(f"Unsupported communication protocol: {protocol}. No server initialized.")            server = None        return server    except Exception as e:        logging.error(f"An error occurred while initializing communication: {e}", exc_info=True)        return Nonedef init_communication_influx_db(server, grid_name):    """    Initializes communication with an InfluxDB database and sets up the necessary client, write API, and configuration    for data transmission in a power grid analysis application.    The function reads the database connection parameters (URL, token, organization, and bucket) from environment    variables and stores the InfluxDB client, write API, and configuration details in the `server` dictionary.    :param server: Dictionary that holds various configuration settings, to be updated with InfluxDB connection info.    :param grid_name: Name of the power grid, to be used as a tag when writing data to the database.    :return: The updated `server` dictionary containing the initialized InfluxDB client and other settings.    """    try:        logging.info("Initializing communication with InfluxDB.")        # Read database connection parameters from environment variables        url = os.getenv("INFLUXDB_URL")  # InfluxDB URL from environment variable        token = os.getenv("INFLUXDB_TOKEN")  # Authentication token for accessing InfluxDB        org = os.getenv("INFLUXDB_ORG")  # Organization name for InfluxDB from environment variable        bucket = os.getenv("INFLUXDB_BUCKET")  # Bucket name (database) in InfluxDB for data storage        if not all([url, token, org, bucket]):            logging.error("Missing InfluxDB configuration in environment variables. Initialization failed.")            return server        # Initialize the InfluxDB client        client = InfluxDBClient(url=url, token=token, org=org)        logging.info(f"InfluxDB client initialized with URL: {url}, Org: {org}, and Bucket: {bucket}")        # Store the InfluxDB client and other relevant settings in the server dictionary        server['influxdb_client'] = client        server['write_api'] = client.write_api(write_options=WriteOptions(batch_size=1))        server['bucket'] = bucket        server['org'] = org        server['grid_name'] = grid_name        logging.info("InfluxDB communication initialized successfully.")        return server    except Exception as e:        logging.error(f"An error occurred during InfluxDB communication initialization: {e}", exc_info=True)        return server